class HomeRepositoryImpl() : HomeRepository {

    override suspend fun getRestaurants(): Results<List<Restaurant>> {
        return Results.Success(restaurantList)
    }

    override suspend fun getAds(): Results<List<Advertisement>> {
        return Results.Success(adList)
    }

    override suspend fun getFoodItems(): Results<List<FoodItem>> {
        return Results.Success(recommendedList)
    }

    override fun getRestaurantFromName(name: String): Restaurant? {
        return restaurantList.find {
            it.name == name
        }
    }
}

class LoginRepositoryImpl(context: Context) : PrefsDataStore(context = context, PREF_LOGIN_STATE), LoginRepository  {


    companion object {
        const val PREF_LOGIN_STATE = "user_login_state_pref"
        private val LOGIN_STATE_KEY = booleanPreferencesKey("user_login_state")

    }


    override val loginState: Flow<Boolean>
        get() = mDataStore.data.map { preferences ->
            val uiMode = preferences[LOGIN_STATE_KEY] ?: false
            uiMode
        }

    override suspend fun toggleLoginState() {
        mDataStore.edit { preferences ->
            val loginState = preferences[LOGIN_STATE_KEY] ?: false
            preferences[LOGIN_STATE_KEY] = !loginState
        }
    }




}

abstract class PrefsDataStore(context: Context, fileName: String) {
    private val Context.dataStore: DataStore<Preferences> by preferencesDataStore(fileName)
    val mDataStore: DataStore<Preferences> = context.dataStore
}

sealed class Results<out R> {
    data class Success<out T>(val data: T) : Results<T>()
    data class Error(val exception: Exception) : Results<Nothing>()
}

fun <T> Results<T>.successOr(fallback: T): T {
    return (this as? Results.Success<T>)?.data ?: fallback
}

class UserDataRepositoryImpl : UserDataRepository {

    private val menuList = mutableSetOf<CartItem>()
    private val cartListItems = cartList.toMutableList()
    private var currentRestaurant: Restaurant? = null


    override suspend fun setRestaurant(restaurant: Restaurant) {
        currentRestaurant = restaurant
        restaurant.menu.forEach {
            menuList.add(CartItem(it, 0))
        }
    }

    override suspend fun getSavedRestaurant(): Flow<Restaurant> = flow {
        if (currentRestaurant != null) {
            emit(currentRestaurant!!)
        }
    }

    override suspend fun getMenuItems(): Flow<List<CartItem>> = flow {
        emit(menuList.toMutableList())
    }

    var list = favouriteList.toMutableList()


    override suspend fun getLikedRestaurants(): Flow<List<Restaurant>> = flow {
        emit(list)
    }

    override suspend fun isRestaurantLiked(restaurant: Restaurant): Flow<Boolean> = flow {
        emit(list.contains(restaurant))
    }

    override suspend fun getCartItems(): Flow<List<CartItem>> = flow {
        emit(cartListItems)
    }
}

